#include<bits/stdc++.h>
using namespace std;
int n,m,r,c;
int a[21][21],ans=1e9,row[21],s1[21],s2[21][21],dp[21][21];
int main()
{
    scanf("%d%d%d%d",&n,&m,&r,&c);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    for(int S=0;S<(1<<n);S++)
    {
        int cnt=0;
        for(int i=0;i<n;i++)
        {
            if(S&(1<<i))
            {
                row[cnt++]=i+1;
            }
        }
        if(cnt!=r)
        {
            continue;
        }
        for(int i=1;i<=m;i++)
        {
            s1[i]=0;
            for(int j=0;j<cnt-1;j++)
            {
                s1[i]+=abs(a[row[j]][i]-a[row[j+1]][i]);
            }
            for(int k=i+1;k<=m;k++)
            {
                s2[i][k]=0;
                for(int j=0;j<cnt;j++)
                {
                    s2[i][k]+=abs(a[row[j]][i]-a[row[j]][k]);
                }
            }
        }
        for(int i=0;i<=m;i++)
        {
            for(int j=0;j<=c;j++)
            {
                dp[i][j]=1e9;
            }
        }
        dp[0][0]=0;
        for(int i=1;i<=m;i++)
        {
            dp[i][1]=s1[i];
            for(int j=2;j<=c;j++)
            {
                for(int k=1;k<i;k++)
                {
                    dp[i][j]=min(dp[i][j],dp[k][j-1]+s1[i]+s2[k][i]);
                }
            }
            ans=min(ans,dp[i][c]);
        }
    }
    printf("%d",ans);
    return 0;
}
